#!/usr/bin/python3
import os, sys
with open ('/tmp/e2kodi.log', 'a') as f: print('PRZYKLAD: emukodiCLI -l debug [ -o /tmp/fileName] "url" best', file=f)
#/usr/sbin/emukodiCLI -l debug -p /iptvplayer_rootfs/usr/bin/exteplayer3 --player-http --verbose-player 'http://cdn-s-lb2.pluscdn.pl/ch/1456452/129/dash/ffe2048f/live.mpd' best -decryption_key 0af2b5f2450474207f6761adc9dc635e
#os.nice(-10)

idx = 0
for argument in sys.argv:
    if argument.startswith('http%3a//127.0.0.1%3a8088/'):
        argument = argument[len('http%3a//127.0.0.1%3a8088/'):]
    elif argument.startswith('http://127.0.0.1%3a8088/'):
        argument = argument[len('http://127.0.0.1%3a8088/'):]
    elif argument.startswith('http://127.0.0.1:8088/'):
        argument = argument[len('http://127.0.0.1:8088/'):]
    if argument.startswith('http%3a') or argument.startswith('https%3a'):
        argument = argument.split(':')[0]
    argument = argument.replace('%3a',':').replace('-decryption_key', '-decryption-key')
    sys.argv[idx] = argument
    idx += 1

pid = os.getpid()
fname = '/var/run/%s.pid' % os.path.basename(__file__).replace('.pyc', '').replace('.pyo', '').replace('.py', '')
with open(fname , 'w') as f:
    f.write(str(pid))
    f.close()

import emukodislink_cli.main
#print('main()')
emukodislink_cli.main.main()
